%PsiPar%	Initial parameter values for PSI	%	3/2/99	CCC	Pull out from PsiInit% Set up the threshold range for estimationminThres = log10(0.01); maxThres = log10(1); thresStep = 0.05;% Set up the slope range for estimationminSlope=1;maxSlope=4;slopeStep=.25; % octave units% Possible contrast to be presented in an experimental sectionminCont=log10(.01);maxCont=log10(1);contStep = 0.05;miss = 0.04;	% miss levelgamma = .5;		% Guessing factor. It is 0.5 for 2AFC